member.example:
Bind an ObservableDictionaryViewModelBinder<TKey, TViewModel> using a serialized field — the target factory is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ObservableDictionaryViewModelBinder<string, ItemViewModel> _items;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public ObservableDictionary<string, ItemViewModel> _items;
    }

Bind an ObservableDictionaryViewModelBinder<TKey, TViewModel, TView, TViewFactory> by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ObservableDictionaryViewModelBinder<string, ItemViewModel, ItemView, CustomKeyedFactory> _items
            = new(new CustomKeyedFactory());
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public ObservableDictionary<string, ItemViewModel> _items;
    }
